
package com.example.taxgap.domain.dto.report; import java.math.BigDecimal; public class CustomerTaxSummaryRow { private String customerId; private BigDecimal totalAmount; private BigDecimal totalReportedTax; private BigDecimal totalExpectedTax; private BigDecimal totalTaxGap; private double complianceScore; public CustomerTaxSummaryRow(String c, BigDecimal a, BigDecimal rt, BigDecimal et, BigDecimal tg, double s){customerId=c; totalAmount=a; totalReportedTax=rt; totalExpectedTax=et; totalTaxGap=tg; complianceScore=s;} public String getCustomerId(){return customerId;} public BigDecimal getTotalAmount(){return totalAmount;} public BigDecimal getTotalReportedTax(){return totalReportedTax;} public BigDecimal getTotalExpectedTax(){return totalExpectedTax;} public BigDecimal getTotalTaxGap(){return totalTaxGap;} public double getComplianceScore(){return complianceScore;} }
